+package web
+
+import (
+	"encoding/json"
+	"log/slog"
+	"os"
+	"path/filepath"
+	"sync"
+)
+
+// ReloadStatus is the outcome of a transactional configuration reload.
+// LastReloadID is an RFC3339 timestamp identifying the reload attempt.
+type ReloadStatus struct {
+	LastReloadID         string           `json:"last_reload_id"`
+	LastReloadSuccessful bool             `json:"last_reload_successful"`
+	ErrorCategory        string           `json:"error_category"`
+	ErrorMessage         string           `json:"error_message"`
+	AppliedReloaders     []string         `json:"applied_reloaders"`
+	RollbackAttempted    bool             `json:"rollback_attempted"`
+	RollbackSuccessful   bool             `json:"rollback_successful"`
+	FailedReloader       string           `json:"failed_reloader"`
+	ReloaderTimingsMS    map[string]int64 `json:"reloader_timings_ms"`
+}
+
+// ReloadStatusTracker keeps the latest outcome and, when enabled, stores it on disk.
+type ReloadStatusTracker struct {
+	mu      sync.RWMutex
+	status  ReloadStatus
+	path    string
+	enabled bool
+	logger  *slog.Logger
+}
+
+func NewReloadStatusTracker(tsdbDir string, enabled bool, logger *slog.Logger) *ReloadStatusTracker {
+	t := &ReloadStatusTracker{
+		status: ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}},
+		enabled: enabled,
+		logger:  logger,
+	}
+	if !enabled {
+		return t
+	}
+	t.path = filepath.Join(tsdbDir, "reload_status.json")
+	b, err := os.ReadFile(t.path)
+	if err != nil {
+		if !os.IsNotExist(err) && logger != nil {
+			logger.Warn("Unable to read persisted reload status", "err", err)
+		}
+		return t
+	}
+	var status ReloadStatus
+	if err := json.Unmarshal(b, &status); err != nil || !validReloadStatus(status) {
+		if logger != nil {
+			logger.Warn("Unable to decode persisted reload status", "err", err)
+		}
+		return t
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]int64{}
+	}
+	t.status = status
+	return t
+}
+
+func validReloadStatus(s ReloadStatus) bool {
+	switch s.ErrorCategory {
+	case "none", "load_error", "apply_error", "rollback_error":
+		return true
+	default:
+		return false
+	}
+}
+
+func (t *ReloadStatusTracker) Get() ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	return cloneReloadStatus(t.status)
+}
+
+func (t *ReloadStatusTracker) Set(status ReloadStatus) {
+	status = cloneReloadStatus(status)
+	t.mu.Lock()
+	t.status = status
+	t.mu.Unlock()
+	if !t.enabled {
+		return
+	}
+	b, err := json.Marshal(status)
+	if err == nil {
+		err = os.WriteFile(t.path+".tmp", b, 0o600)
+	}
+	if err == nil {
+		err = os.Rename(t.path+".tmp", t.path)
+	}
+	if err != nil && t.logger != nil {
+		t.logger.Warn("Unable to persist reload status", "err", err)
+	}
+}
+
+func cloneReloadStatus(s ReloadStatus) ReloadStatus {
+	s.AppliedReloaders = append([]string{}, s.AppliedReloaders...)
+	s.ReloaderTimingsMS = make(map[string]int64, len(s.ReloaderTimingsMS))
+	for k, v := range s.ReloaderTimingsMS {
+		s.ReloaderTimingsMS[k] = v
+	}
+	return s
+}
